document.addEventListener("DOMContentLoaded",()=>{const steps=document.querySelectorAll(".wizard-step");const prevBtn=document.getElementById("prev-step-btn");const nextBtn=document.getElementById("next-step-btn");const submitBtn=document.getElementById("submit-booking-btn");const progressPercent=document.getElementById("wizard-progress-percent");const progressLine=document.getElementById("wizard-progress-bar");const stepIndicators=document.querySelectorAll(".step-indicator-item");const statusMessage=document.getElementById("booking-status-message");const wizardContainer=document.getElementById("booking-wizard-container");const successContainer=document.getElementById("booking-success-container");const bookingForm=document.getElementById("consultation-booking-form");const resetBtn=document.getElementById("restart-booking-btn");const localStorageKey="kstudyBookingDraft";const fieldErrorMap={"book-name":"name-error","book-email":"email-error","book-phone":"phone-error","book-program-type":"program-error"};let currentStepIndex=0;const formData={};const fields={fullName:document.getElementById("book-name"),email:document.getElementById("book-email"),phone:document.getElementById("book-phone"),currentLevel:document.getElementById("book-current-level"),programType:document.getElementById("book-program-type"),targetTerm:document.getElementById("book-term"),koreanLevel:document.getElementById("book-korean"),notes:document.getElementById("book-notes")};function updateWizard(){steps.forEach((step,idx)=>{if(idx===currentStepIndex){step.classList.add("active")}else{step.classList.remove("active")}});stepIndicators.forEach((indicator,idx)=>{if(idx<=currentStepIndex){indicator.classList.add("active")}else{indicator.classList.remove("active")}});if(currentStepIndex===0){if(prevBtn)prevBtn.style.display="none"}else{if(prevBtn)prevBtn.style.display="inline-flex"}if(currentStepIndex===steps.length-1){if(nextBtn)nextBtn.style.display="none";if(submitBtn)submitBtn.style.display="inline-flex";populateSummary()}else{if(nextBtn)nextBtn.style.display="inline-flex";if(submitBtn)submitBtn.style.display="none"}const progress=currentStepIndex/(steps.length-1)*100;if(progressLine)progressLine.style.width=`${progress}%`;if(progressPercent)progressPercent.textContent=`${Math.round(progress)}%`;clearStatusMessage()}function validateStep(stepIndex){let isValid=true;const activeStep=steps[stepIndex];activeStep.querySelectorAll(".form-error").forEach(el=>el.classList.remove("show"));activeStep.querySelectorAll("input, select, textarea").forEach(el=>el.classList.remove("input-error"));if(stepIndex===0){if(!fields.fullName||fields.fullName.value.trim()===""){showFieldError(fields.fullName,"name-error");isValid=false}if(!fields.email||!validateEmail(fields.email.value)){showFieldError(fields.email,"email-error");isValid=false}if(!fields.phone||!validatePhone(fields.phone.value)){showFieldError(fields.phone,"phone-error");isValid=false}}else if(stepIndex===1){if(!fields.programType||fields.programType.value===""){showFieldError(fields.programType,"program-error");isValid=false}}return isValid}function validateEmail(email){return/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)}function validatePhone(phone){return/^[+?\d\s()\-]{7,25}$/.test(phone.trim())}function showFieldError(fieldEl,errorId){if(fieldEl)fieldEl.classList.add("input-error");const errorEl=document.getElementById(errorId);if(errorEl)errorEl.classList.add("show")}function setStatusMessage(message,type="info"){if(!statusMessage)return;statusMessage.textContent=message;statusMessage.className=`booking-status-message ${type}`}function clearStatusMessage(){if(!statusMessage)return;statusMessage.textContent="";statusMessage.className="booking-status-message"}function setButtonLoading(loading){if(!submitBtn)return;if(loading){submitBtn.disabled=true;submitBtn.classList.add("loading");submitBtn.textContent="Илгээж байна..."}else{submitBtn.disabled=false;submitBtn.classList.remove("loading");submitBtn.textContent="Schedule Consultation 🚀"}}function persistFormState(){if(!window.localStorage)return;const draft={currentStepIndex:currentStepIndex,values:{fullName:fields.fullName?.value||"",email:fields.email?.value||"",phone:fields.phone?.value||"",currentLevel:fields.currentLevel?.value||"",programType:fields.programType?.value||"",targetTerm:fields.targetTerm?.value||"",koreanLevel:fields.koreanLevel?.value||"",notes:fields.notes?.value||""}};window.localStorage.setItem(localStorageKey,JSON.stringify(draft))}function clearDraftState(){if(!window.localStorage)return;window.localStorage.removeItem(localStorageKey)}function restoreFormState(){if(!window.localStorage)return;const saved=window.localStorage.getItem(localStorageKey);if(!saved)return;try{const draft=JSON.parse(saved);if(draft&&draft.values){Object.entries(draft.values).forEach(([key,value])=>{if(fields[key]&&typeof value==="string"){fields[key].value=value}})}if(typeof draft.currentStepIndex==="number"){currentStepIndex=Math.min(Math.max(draft.currentStepIndex,0),steps.length-1)}}catch(error){console.warn("Unable to restore booking draft:",error)}}function populateSummary(){const summaryName=document.getElementById("summary-name");const summaryEmail=document.getElementById("summary-email");const summaryPhone=document.getElementById("summary-phone");const summaryProgram=document.getElementById("summary-program");const summaryTerm=document.getElementById("summary-term");const summaryKorean=document.getElementById("summary-korean");const summaryNotes=document.getElementById("summary-notes");if(summaryName)summaryName.textContent=fields.fullName.value.trim();if(summaryEmail)summaryEmail.textContent=fields.email.value.trim();if(summaryPhone)summaryPhone.textContent=fields.phone.value.trim();if(summaryProgram){const selectedOption=fields.programType.options[fields.programType.selectedIndex];summaryProgram.textContent=selectedOption?selectedOption.text:fields.programType.value}if(summaryTerm){const selectedOption=fields.targetTerm.options[fields.targetTerm.selectedIndex];summaryTerm.textContent=selectedOption?selectedOption.text:fields.targetTerm.value}if(summaryKorean){const selectedOption=fields.koreanLevel.options[fields.koreanLevel.selectedIndex];summaryKorean.textContent=selectedOption?selectedOption.text:fields.koreanLevel.value}if(summaryNotes){const noteText=fields.notes.value.trim();const notesRow=summaryNotes.closest(".summary-data-item");if(noteText.length>0){summaryNotes.textContent=noteText;notesRow?.classList.remove("hidden")}else{summaryNotes.textContent="";notesRow?.classList.add("hidden")}}}Object.values(fields).forEach(field=>{if(!field)return;const eventType=field.tagName.toLowerCase()==="select"?"change":"input";field.addEventListener(eventType,()=>{field.classList.remove("input-error");const errorId=fieldErrorMap[field.id];if(errorId){const errorEl=document.getElementById(errorId);if(errorEl)errorEl.classList.remove("show")}clearStatusMessage();persistFormState()})});if(nextBtn){nextBtn.addEventListener("click",()=>{if(validateStep(currentStepIndex)){if(currentStepIndex<steps.length-1){currentStepIndex+=1;updateWizard();persistFormState()}}else{setStatusMessage("Та формын алдааг засна уу.","error")}})}if(prevBtn){prevBtn.addEventListener("click",()=>{if(currentStepIndex>0){currentStepIndex-=1;updateWizard();persistFormState()}})}if(bookingForm){bookingForm.addEventListener("submit",e=>{e.preventDefault();if(!validateStep(currentStepIndex)){setStatusMessage("Та формын алдааг засна уу.","error");return}setButtonLoading(true);setStatusMessage("Таны хүсэлт илгээж байна...","info");setTimeout(()=>{Object.keys(fields).forEach(key=>{if(fields[key]){formData[key]=fields[key].value.trim()}});clearDraftState();if(wizardContainer)wizardContainer.style.display="none";if(successContainer){successContainer.style.display="flex";successContainer.classList.add("fade-in")}triggerConfetti();setButtonLoading(false)},1100)})}if(resetBtn){resetBtn.addEventListener("click",()=>{if(bookingForm)bookingForm.reset();currentStepIndex=0;clearDraftState();clearStatusMessage();setButtonLoading(false);if(successContainer)successContainer.style.display="none";if(wizardContainer)wizardContainer.style.display="block";updateWizard()})}restoreFormState();updateWizard();function triggerConfetti(){const canvas=document.getElementById("confetti-canvas");if(!canvas)return;canvas.width=canvas.parentElement.clientWidth;canvas.height=canvas.parentElement.clientHeight||450;const ctx=canvas.getContext("2d");let particles=[];const colors=["#3b82f6","#4f46e5","#ec4899","#10b981","#f59e0b"];for(let i=0;i<120;i+=1){particles.push({x:canvas.width/2,y:canvas.height+20,radius:Math.random()*5+4,color:colors[Math.floor(Math.random()*colors.length)],vx:Math.random()*12-6,vy:Math.random()*-12-8,gravity:.25,rotation:Math.random()*360,rotationSpeed:Math.random()*6-3,opacity:1})}function animate(){let activeParticles=0;ctx.clearRect(0,0,canvas.width,canvas.height);particles.forEach(p=>{if(p.opacity<=0)return;activeParticles+=1;p.x+=p.vx;p.y+=p.vy;p.vy+=p.gravity;p.rotation+=p.rotationSpeed;p.opacity-=.008;ctx.save();ctx.translate(p.x,p.y);ctx.rotate(p.rotation*Math.PI/180);ctx.globalAlpha=p.opacity;ctx.fillStyle=p.color;ctx.fillRect(-p.radius,-p.radius,p.radius*2,p.radius*1.5);ctx.restore()});if(activeParticles>0){requestAnimationFrame(animate)}}animate()}});